#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL;
typedef unsigned long long uLL;
typedef unsigned uInt;
typedef unsigned short uShort;
namespace jr_zlw
{
	inline int read()
	{
		int res=0;char ch=getchar();bool flag=0;
		while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
		return flag ? -res : res ;
	}
	template<typename T> inline T min(const T &x,const T &y){return x<y?x:y;}
	template<typename T> inline T max(const T &x,const T &y){return x>y?x:y;}
	template<typename T> inline void swap(T &x,T &y){T tmp=x;x=y;y=tmp;}
	inline void rd(int &res)
	{
		res=0;char ch=getchar();bool flag=0;
		while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
		flag ? res = -res : 0 ;
	}
	inline void rd(long long &res)
	{
		res=0;char ch=getchar();bool flag=0;
		while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
		flag ? res = -res : 0 ;
	}
	inline void rd(short &res)
	{
		res=0;char ch=getchar();bool flag=0;
		while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
		flag ? res = -res : 0 ;
	}
	inline void rd(uInt &res)
	{
		res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	}
	inline void rd(uLL &res)
	{
		res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	}
	inline void rd(uShort &res)
	{
		res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	}
	inline int rd(char *s)
	{
		int p=-1;char ch=getchar();while(ch==' '||ch=='\n'||ch=='\r')ch=getchar();
		if(ch==-1)return -1;while(ch!=' '&&ch!='\n'&&ch!='\r')s[++p]=ch,ch=getchar();return p;
	}
	inline void rd(bool &res){char ch;do ch=getchar();while(ch!='0'&&ch!='1');res=(ch=='1');}
	inline void rd(char &ch){do ch=getchar();while(ch==' '||ch=='\n'||ch=='\r');}
	const int Mod=1e9+7,INF=0x3f3f3f3f;const long long INFll=4e18;
	template<typename T> inline T SQ(const T &x){return x*x;}
	template<typename T> inline void DN(T &x){x>Mod?x-=Mod:0;}
	template<typename T> inline void UP(T &x){x<0?x+=Mod:0;}
	template<typename T> inline T gcd(const T &a,const T &b){return b?gcd(b,a%b):a;}
	template<typename T> inline T lcm(const T &a,const T &b){return a/gcd(a,b)*b;}
	template<typename T> inline T qpow(T a,T b){T r=1;while(b){if(b&1)r=1ll*r*a%Mod;a=1ll*a*a%Mod;b=b>>1;}return r;}
	const int N=17;bool tmp[N][N],mp[N][N];int n,ans=INF,cnt;
	inline void check()
	{
		int res=0;rep(1,n,i)res+=(tmp[1][i]&&!mp[1][i]);
		for(int i=1;i<n;++i)rep(1,n,j)
		{
			tmp[i+1][j]=(tmp[i][j-1]^tmp[i][j+1]^tmp[i-1][j]);
			if(!tmp[i+1][j]&&mp[i+1][j])return;
			else res+=(tmp[i+1][j]&&!mp[i+1][j]);
		}
		ans=min(ans,res);return;
	}
	inline void dfs(int p)
	{
		if(p>n)return check();tmp[1][p]=true;dfs(p+1);
		if(!mp[1][p])tmp[1][p]=false,dfs(p+1);
	}
	inline void mian()
	{
		memset(tmp,0,sizeof(tmp));memset(mp,0,sizeof(mp));
		rd(n);rep(1,n,i)rep(1,n,j)rd(mp[i][j]);
		ans=INF;dfs(1);printf("Case %d: %d\n",++cnt,ans==INF?-1:ans);
	}
}
int main()
{
	unsigned int T;jr_zlw::rd(T);
	while(T--)jr_zlw::mian();return 0;
}
